class Solution:
    def isValid(self, board: list[list[int]]) -> bool:
        n = len(board)
        for i in range(n):
            row = board[i]
            for j in range(n):
                if row[j] == 0: continue
                for k in range(n):
                    for l in range(n):
                        if k != i and board[k][l] == row[j]: return False
        return True

