#include <iostream>
#include <vector>
using namespace std;

bool is_valid(vector<vector<int>>& board) {
    int n = board.size();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (board[i][j] == 0) continue;
            for (int k = 0; k < n; k++) {
                for (int l = 0; l < n; l++) {
                    if (k != i && board[k][l] == board[i][j]) return false;
                }
            }
        }
    }
    return true;
}

int main() {
    int n;
    cin >> n;
    vector<vector<int>> board(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> board[i][j];
        }
    }
    cout << (is_valid(board) ? "True" : "False") << endl;
    return 0;
}
